class AnnotationRuleReproductionTest {
    private val annotationRuleAssertThat = assertThatRule { AnnotationRule() }

    @Test
    fun `Given annotations before class constructor`() {
        val code =
            """
            data class Foo @Bar1 @Bar2("bar") @Bar3 @Bar4 constructor(private val foobar: Int) {
                fun foo(): String = "foo"
            }
            """.trimIndent()
        val formattedCode =
            """
            data class Foo
                @Bar1
                @Bar2("bar")
                @Bar3
                @Bar4
                constructor(private val foobar: Int) {
                fun foo(): String = "foo"
            }
            """.trimIndent()
        annotationRuleAssertThat(code)
            .isFormattedAs(formattedCode)
    }

    @Test
    fun `Given annotations on type projections`() {
        val code =
            """
            val fooBar: FooBar<String, @Foo String, @Foo @Bar String, @Bar("bar") @Foo String> = FooBar()
            """.trimIndent()
        val formattedCode =
            """
            val fooBar: FooBar<
                String,
                @Foo String,
                @Foo @Bar
                String,
                @Bar("bar")
                @Foo
                String
                > = FooBar()
            """.trimIndent()

        // Note: This test might require other rules like IndentationRule or WrappingRule 
        // to fully match the expected formatting if newlines are introduced. 
        // But AnnotationRule should at least trigger the wrapping of annotations.
        // For now, I'm just checking if AnnotationRule does its part.

        annotationRuleAssertThat(code)
            .addAdditionalRuleProvider { IndentationRule() }
            .addAdditionalRuleProvider { WrappingRule() }
            .isFormattedAs(formattedCode)
    }
}
